import React from 'react';

const ImageTextRow = ({ src, alt, link, text, reverse }) => {
  return (
    <a
      href={link}
      target="_blank"
      rel="noopener noreferrer"
      style={{
        ...styles.row,
        flexDirection: reverse ? 'row-reverse' : 'row',
      }}
    >
      <img src={src} alt={alt} style={styles.image} />
      <div style={styles.textContainer}>
        <p style={styles.text}>{text}</p>
      </div>
    </a>
  );
};

const ContactoPage = () => {
  const items = [
    {
      src: '/media/contactoPage/LP.png',
      alt: 'Entrada UCB',
      link: 'https://www.ucb.edu.bo/',
      text: 'Bienvenido a la Universidad Católica Boliviana',
    },
    {
      src: '/media/contactoPage/SIS - H.png',
      alt: 'Logo SIS',
      link: 'https://www.ucb.edu.bo/contacto',
      text: 'Sistema de Información y Servicios',
    },
    {
      src: '/media/contactoPage/IIE - H.png',
      alt: 'Equipo ADM',
      link: 'https://www.ucb.edu.bo/nosotros',
      text: 'Instituto de Investigaciones y Estudios',
    },
  ];

  return (
    <main style={styles.page}>
      <h1 style={styles.title}>UNIVERSIDAD CATÓLICA BOLIVIANA</h1>
      <div style={styles.container}>
        {items.map((item, index) => (
          <ImageTextRow
            key={index}
            {...item}
            reverse={index % 2 === 1} // alterna orden en filas pares
          />
        ))}
      </div>
    </main>
  );
};

const styles = {
  page: {
    backgroundColor: '#F8F0E3',
    minHeight: '100vh',
    padding: '3rem 1rem',
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
    color: '#052018',
  },
  title: {
    fontSize: '3rem',
    fontWeight: '900',
    marginBottom: '3rem',
    textAlign: 'center',
  },
  container: {
    display: 'flex',
    flexDirection: 'column',
    gap: '3rem',
    maxWidth: 960,
    margin: '0 auto',
  },
  row: {
    display: 'flex',
    alignItems: 'center',
    gap: '2rem',
    textDecoration: 'none',
    color: 'inherit',
  },
  image: {
    width: 200,
    height: 200,
    objectFit: 'cover',
    borderRadius: 16,
    flexShrink: 0,
    boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
    cursor: 'pointer',
  },
  textContainer: {
    flex: 1,
  },
  text: {
    fontSize: '1.25rem',
    fontWeight: '600',
  },
};

export default ContactoPage;
